with open(file_path, 'r') as f:
    businesses = json.load(f)

# Filter businesses that accept credit cards and properly extract categories
credit_card_businesses = []
all_categories = []

for business in businesses:
    if business.get('attributes') and isinstance(business['attributes'], dict):
        if business['attributes'].get('BusinessAcceptsCreditCards') == 'True':
            business_id = business['business_id']

            # Parse categories from description
            description = business.get('description', '')
            categories = []

            if description:
                # Find the part with categories (after "services in" or "services including")
                category_part = None

                if 'services in' in description:
                    category_part = description.split('services in')[-1]
                elif 'services, including' in description:
                    category_part = description.split('services, including')[-1]
                elif 'services including' in description:
                    category_part = description.split('services including')[-1]
                elif 'offers a' in description and (' in ' in description or ' including ' in description):
                    # More general pattern
                    offers_part = description.split('offers a')[-1]
                    if ' in ' in offers_part:
                        category_part = offers_part.split(' in ')[-1]
                    elif ' including ' in offers_part:
                        category_part = offers_part.split(' including ')[-1]

                if category_part:
                    # Clean up the string
                    category_part = category_part.strip()
                    if category_part.endswith('.'):
                        category_part = category_part[:-1]

                    # Split by commas and clean
                    parts = [p.strip() for p in category_part.split(',')]
                    categories = []

                    for part in parts:
                        # Handle "and" before last category
                        if ' and ' in part:
                            # Split on " and " but preserve both
                            sub_parts = [p.strip() for p in part.split(' and ')]
                            categories.extend(sub_parts)
                        else:
                            categories.append(part)

                    # Clean up categories - remove empty strings and common phrases
                    categories = [cat for cat in categories if cat and cat not in ['', 'offering', 'providing']]

                    # If no clear categories found, use a generic category based on business name
                    if not categories and 'Restaurant' in business['name'] or 'Cafe' in business['name'] or 'Bar' in business['name']:
                        categories = ['Restaurants']
                    elif not categories and 'Nail' in business['name']:
                        categories = ['Nail Salons']
                    elif not categories and 'Hair' in business['name'] or 'Salon' in business['name']:
                        categories = ['Hair Salons']
                    elif not categories and ('Medical' in business['name'] or 'Care' in business['name']):
                        categories = ['Health & Medical']

            credit_card_businesses.append({
                'business_id': business_id,
                'name': business['name'],
                'categories': categories,
                'review_count': int(business.get('review_count', 0))
            })

            all_categories.extend(categories)

# Count businesses per category
category_counts = {}
for business in credit_card_businesses:
    for category in business['categories']:
        if category:  # Only count non-empty categories
            category_counts[category] = category_counts.get(category, 0) + 1

# Sort by count to find top categories
top_categories = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)

print('__RESULT__:')
print(json.dumps({
    'credit_card_businesses': credit_card_businesses[:10],  # Sample for debugging
    'top_categories': top_categories[:20],
    'total_businesses': len(credit_card_businesses)
}, indent=2))"}

